class Solution:
    def numberOfArrays(self, s: str, k: int) -> int:
        MOD = 10**9 + 7
        n = len(s)
        dp = [0] * (n + 1)
        dp[0] = 1
        for i in range(1, n + 1):
            for j in range(i):
                if int(s[j:i]) <= k:
                    dp[i] = (dp[i] + dp[j] * (k - int(s[j:i]) + 1)) % MOD
        return dp[n]

